mapper.select:
SELECT DISTINCT t4.* FROM t_user t1 INNER JOIN t_user_role t2 ON t1.`user_id` = t2.`user_id` INNER JOIN t_role_menu t3 ON t2.`role_id` = t3.`role_id` INNER JOIN t_menu t4 ON t3.`menu_id` = t4.`id` WHERE t1.`user_id` = #{userId} and t4.status = true
and t2.`comp_id` = #{compID}
ORDER BY t4.pid, t4.sort ASC
